import React, { useEffect, useRef, useState } from 'react';
import { Link } from 'react-router-dom';

/* ─── Reveal Hook ───────────────── */
function useReveal() {
  const ref = useRef(null);
  const [visible, setVisible] = useState(false);

  useEffect(() => {
    const el = ref.current;
    if (!el) return;

    const obs = new IntersectionObserver(
      ([entry]) => {
        if (entry.isIntersecting) {
          setVisible(true);
          obs.disconnect();
        }
      },
      { threshold: 0.15 }
    );

    obs.observe(el);
    return () => obs.disconnect();
  }, []);

  return [ref, visible];
}

/* ─── Reveal Wrapper ───────────── */
function Reveal({ children, delay = 0 }) {
  const [ref, visible] = useReveal();

  return (
    <div
      ref={ref}
      style={{
        opacity: visible ? 1 : 0,
        transform: visible ? 'translateY(0)' : 'translateY(30px)',
        transition: `all 0.7s cubic-bezier(.22,1,.36,1) ${delay}s`,
      }}
    >
      {children}
    </div>
  );
}

/* ─── Main Component ──────────── */
export default function About() {
  const [scrolled, setScrolled] = useState(false);

  useEffect(() => {
    const onScroll = () => setScrolled(window.scrollY > 30);
    window.addEventListener('scroll', onScroll);
    return () => window.removeEventListener('scroll', onScroll);
  }, []);

  const sections = [
    {
      icon: '🎓',
      title: 'For Students',
      desc: 'Job matching, career roadmap, AI advisor, learning courses, CV analyzer, certifications, and badges.',
    },
    {
      icon: '🏢',
      title: 'For Companies',
      desc: 'Post jobs, filter applicants, schedule interviews, compare candidates, view analytics, and mentorship programs.',
    },
    {
      icon: '🛡️',
      title: 'For Admins',
      desc: 'Full management of users, jobs, courses, and platform analytics with a powerful dashboard.',
    },
    {
      icon: '⚡',
      title: 'Built With',
      desc: 'React.js, Express.js, MySQL, JWT Authentication, and lots of coffee ☕',
    },
  ];

  return (
    <div style={{ background: 'var(--bg-base)', color: 'var(--text-primary)' }}>

      {/* NAV */}
      <nav
        style={{
          position: 'fixed',
          top: 0,
          width: '100%',
          height: 70,
          display: 'flex',
          justifyContent: 'space-between',
          alignItems: 'center',
          padding: '0 40px',
          backdropFilter: 'blur(18px)',
          background: scrolled
            ? 'rgba(10,12,22,0.85)'
            : 'rgba(10,12,22,0.5)',
          borderBottom: scrolled
            ? '1px solid rgba(255,255,255,0.05)'
            : 'transparent',
          zIndex: 999,
          transition: 'all .3s ease',
        }}
      >
        <Link to="/" style={{ fontWeight: 800 }}>StudentBridge</Link>

        <div style={{ display: 'flex', gap: 20 }}>
          <Link to="/contact">Contact</Link>
          <Link to="/login">Sign In</Link>
          <Link to="/register" className="btn btn-primary">
            Get Started
          </Link>
        </div>
      </nav>

      {/* HERO */}
      <section
        style={{
          paddingTop: 120,
          paddingBottom: 60,
          textAlign: 'center',
          position: 'relative',
        }}
      >
        <div
          style={{
            position: 'absolute',
            inset: 0,
            background:
              'radial-gradient(circle at 20% 20%, rgba(79,142,247,0.15), transparent 60%)',
          }}
        />

        <div style={{ maxWidth: 800, margin: '0 auto', padding: '0 24px', position: 'relative' }}>
          <Reveal>
            <span
              style={{
                padding: '6px 16px',
                borderRadius: 20,
                background: 'rgba(79,142,247,0.1)',
                color: 'var(--accent-primary)',
                fontSize: '0.8rem',
                fontWeight: 600,
              }}
            >
              About Us
            </span>
          </Reveal>

          <Reveal delay={0.2}>
            <h1 style={{ marginTop: 20, fontSize: '2.5rem', fontWeight: 800 }}>
              About StudentBridge
            </h1>
          </Reveal>

          <Reveal delay={0.4}>
            <p
              style={{
                marginTop: 20,
                fontSize: '1.05rem',
                color: 'var(--text-secondary)',
                lineHeight: 1.7,
              }}
            >
              StudentBridge is a graduation project designed to bridge the gap between students and companies through smart job matching, AI tools, and career-focused learning.
            </p>
          </Reveal>
        </div>
      </section>

      {/* MISSION */}
      <section style={{ padding: '40px 24px' }}>
        <Reveal>
          <div
            style={{
              maxWidth: 800,
              margin: '0 auto',
              padding: 30,
              borderRadius: 16,
              background: 'var(--bg-card)',
              border: '1px solid var(--border)',
              textAlign: 'center',
              transition: '0.3s',
            }}
          >
            <h3 style={{ marginBottom: 10 }}>🎯 Our Mission</h3>
            <p style={{ color: 'var(--text-secondary)' }}>
              Help every student land their first job by providing the right tools, guidance, and opportunities — all in one place.
            </p>
          </div>
        </Reveal>
      </section>

      {/* FEATURES GRID */}
      <section style={{ padding: '60px 24px' }}>
        <div style={{ maxWidth: 1000, margin: '0 auto' }}>
          <div
            style={{
              display: 'grid',
              gridTemplateColumns: 'repeat(2,1fr)',
              gap: 20,
            }}
          >
            {sections.map((item, i) => (
              <Reveal key={i} delay={i * 0.1}>
                <div
                  style={{
                    padding: 24,
                    borderRadius: 16,
                    background: 'var(--bg-card)',
                    border: '1px solid var(--border)',
                    transition: 'all 0.25s ease',
                  }}
                  onMouseEnter={e => {
                    e.currentTarget.style.transform = 'translateY(-6px)';
                    e.currentTarget.style.boxShadow = '0 12px 40px rgba(0,0,0,0.4)';
                  }}
                  onMouseLeave={e => {
                    e.currentTarget.style.transform = 'translateY(0)';
                    e.currentTarget.style.boxShadow = 'none';
                  }}
                >
                  <div style={{ fontSize: 28, marginBottom: 10 }}>{item.icon}</div>
                  <h4 style={{ marginBottom: 6 }}>{item.title}</h4>
                  <p style={{ fontSize: '0.9rem', color: 'var(--text-secondary)' }}>
                    {item.desc}
                  </p>
                </div>
              </Reveal>
            ))}
          </div>
        </div>
      </section>

      {/* FOOTER */}
      <footer style={{ padding: 40, textAlign: 'center', borderTop: '1px solid var(--border)' }}>
        © 2025 StudentBridge
      </footer>
    </div>
  );
}
